sheet.script:
                    function aiGoTab(tab, el) {
                        ['overview','team','sprint'].forEach(function(t) {
                            var panel = document.getElementById('aiTab_' + t);
                            var btn   = document.getElementById('aiNav' + t.charAt(0).toUpperCase() + t.slice(1));
                            if (panel) panel.style.display = (t === tab) ? '' : 'none';
                            if (btn) {
                                btn.style.borderBottom = (t === tab) ? '2px solid #534AB7' : '2px solid transparent';
                                btn.style.color        = (t === tab) ? '#534AB7' : '#666';
                                btn.style.fontWeight   = (t === tab) ? '600' : '400';
                            }
                        });
                    }

                    function aiRenderKpis(data) {
                        var e1 = document.getElementById('aiK1'); if (e1) e1.textContent = data.total_tickets || '—';
                        var e2 = document.getElementById('aiK2'); if (e2) e2.textContent = (data.completion_rate || 0) + '%';
                        var e3 = document.getElementById('aiK3'); if (e3) e3.textContent = data.ml_score || '—';
                        var e4 = document.getElementById('aiK4'); if (e4) e4.textContent = (data.ml_confidence || 0) + '%';
                    }

                    function aiRenderRing(data) {
                        var score = data.ml_score || 0;
                        var ring  = document.getElementById('aiRingCircle');
                        var val   = document.getElementById('aiRingVal');
                        var badge = document.getElementById('aiHealthBadge');
                        var conf  = document.getElementById('aiConfVal');
                        if (!ring) return;
                        var color = score >= 70 ? '#1D9E75' : score >= 45 ? '#BA7517' : '#E24B4A';
                        ring.setAttribute('stroke-dashoffset', Math.round(289 * (1 - score / 100)));
                        ring.setAttribute('stroke', color);
                        if (val)   val.textContent  = score;
                        if (conf)  conf.textContent  = (data.ml_confidence || 0) + '%';
                        if (badge) {
                            if (score >= 70) {
                                badge.style.background = '#E1F5EE'; badge.style.color = '#085041'; badge.textContent = 'Healthy';
                            } else if (score >= 45) {
                                badge.style.background = '#FAEEDA'; badge.style.color = '#633806'; badge.textContent = 'At Risk';
                            } else {
                                badge.style.background = '#FCEBEB'; badge.style.color = '#A32D2D'; badge.textContent = 'Critical';
                            }
                        }
                    }

                    function aiRenderFeatures(data) {
                        var el = document.getElementById('aiFeatureBars');
                        if (!el) return;
                        var score = data.ml_score || 0;
                        var feats = [
                            {l:'Completion rate', v:Math.round(score * 0.40), m:40, c:'#534AB7'},
                            {l:'Story pts done',  v:Math.min(30, Math.round(score * 0.30)), m:30, c:'#1D9E75'},
                            {l:'Blocker control', v:Math.max(0, 20 - (data.blocked || 0) * 4), m:20, c:'#BA7517'},
                            {l:'WIP management',  v:Math.max(0, 10 - (data.in_progress || 0)), m:10, c:'#378ADD'},
                        ];
                        el.innerHTML = feats.map(function(f) {
                            return '
' +
                                '
' +
                                '' + f.l + '' +
                                '' + f.v + '/' + f.m + '' +
                                '
' +
                                '
';
                        }).join('');
                    }

                    function aiRenderRisks(data) {
                        var el = document.getElementById('aiRiskRows');
                        if (!el) return;
                        var risks = data.risks || [];
                        var rc = {high:'#A32D2D', medium:'#633806', low:'#085041', info:'#0C447C'};
                        var rb = {high:'#FCEBEB', medium:'#FAEEDA', low:'#E1F5EE', info:'#E6F1FB'};
                        if (!risks.length) {
                            el.innerHTML = '
No risks detected';
                            return;
                        }
                        el.innerHTML = risks.map(function(r) {
                            var lv = (r.level || 'info').toLowerCase();
                            return '
' +
                                '' +
                                r.type + ' — ' + r.detail + '' +
                                '' +
                                r.level + '';
                        }).join('');
                    }

                    function aiRenderRecs(data) {
                        var el = document.getElementById('aiRecCards');
                        if (!el) return;
                        var recs = data.recommendations || [];
                        el.innerHTML = recs.length ? recs.map(function(r, i) {
                            return '
' +
                                '
' + (i + 1) + '' +
                                '' + r + '';
                        }).join('') :
                        '
' +
                        'Run analysis to see recommendations';
                    }

                    function aiRenderTeam(data) {
                        var members = data.members || [];
                        var avg  = members.length ? Math.round(members.reduce(function(a, m) { return a + m.performance_score; }, 0) / members.length) : 0;
                        var high = members.filter(function(m) { return m.performance_score >= 70; }).length;
                        var s1 = document.getElementById('aiTmSize'); if (s1) s1.textContent = members.length;
                        var s2 = document.getElementById('aiTmAvg');  if (s2) s2.textContent = avg;
                        var s3 = document.getElementById('aiTmHigh'); if (s3) s3.textContent = high;
                        var el = document.getElementById('aiTeamRows');
                        if (!el) return;
                        if (!members.length) {
                            el.innerHTML = '
No members found';
                            return;
                        }
                        var medals = ['#1','#2','#3'];
                        el.innerHTML = members.map(function(m, i) {
                            var s  = m.performance_score || 0;
                            var sc = s >= 85 ? '#1D9E75' : s >= 70 ? '#534AB7' : s >= 50 ? '#BA7517' : '#E24B4A';
                            var lv = m.ml_level || m.level || 'N/A';
                            var lc = s >= 85 ? '#085041' : s >= 70 ? '#3C3489' : s >= 50 ? '#633806' : '#A32D2D';
                            var lb = s >= 85 ? '#E1F5EE' : s >= 70 ? '#EEEDFE' : s >= 50 ? '#FAEEDA' : '#FCEBEB';
                            var mt = m.metrics || {};
                            var ini = (m.member_name || 'XX').split(' ').map(function(n) { return n[0]; }).join('').substring(0, 2).toUpperCase();
                            return '
' +
                                '
' +
                                '' + (medals[i] || ('#' + (i + 1))) + '' +
                                '
' + ini + '' +
                                '

' + (m.member_name || 'Unknown') + '' +
                                '' + lv + '' +
                                '
' + (mt.completion_rate || 0) + '%' +
                                '
' + (mt.completed_points || 0) + '' +
                                '
' + (mt.in_progress_count || 0) + '' +
                                '
' + (mt.blocked_count || 0) + '' +
                                '

' + Math.round(s) + '' +
                                '
' +
                                '
';
                        }).join('');
                    }

                    function aiRenderSprint(data) {
                        var vel   = data.velocities || [];
                        var pred  = data.predicted_velocity || {};
                        var prob  = data.completion_prob || 0;
                        var predV = pred.value || 0;
                        var avgV  = vel.length ? Math.round(vel.reduce(function(a, b) { return a + b; }, 0) / vel.length) : 0;
                        var probC = prob >= 70 ? '#0F6E56' : prob >= 50 ? '#854F0B' : '#A32D2D';
                        var e1 = document.getElementById('aiVlAvg');  if (e1) e1.textContent = avgV + ' pts';
                        var e2 = document.getElementById('aiVlPred'); if (e2) e2.textContent = predV + ' pts';
                        var e3 = document.getElementById('aiVlProb');
                        if (e3) { e3.textContent = prob + '%'; e3.style.color = probC; }
                        var barsEl = document.getElementById('aiVelBars');
                        if (barsEl && vel.length) {
                            var maxV = Math.max.apply(null, vel.concat([predV, 1]));
                            barsEl.innerHTML = vel.map(function(v, i) {
                                var hp = Math.round(v / maxV * 100);
                                return '
' +
                                    '
' + v + '' +
                                    '
' +
                                    '
S' + (i + 1) + '';
                            }).join('') + (predV ? (function() {
                                var ph = Math.round(predV / maxV * 100);
                                return '
' +
                                    '
' + predV + '' +
                                    '
' +
                                    '
Pred';
                            })() : '');
                        }
                        var anom  = data.anomalies || [];
                        var abox  = document.getElementById('aiAnomalyBox');
                        var arows = document.getElementById('aiAnomalyRows');
                        if (abox) abox.style.display = anom.length ? '' : 'none';
                        if (arows && anom.length) {
                            var ac = {danger:'#A32D2D', warning:'#633806', info:'#0C447C'};
                            var ab = {danger:'#FCEBEB', warning:'#FAEEDA', info:'#E6F1FB'};
                            arows.innerHTML = anom.map(function(a) {
                                var lv = a.level || 'warning';
                                return '
' + a.message + '';
                            }).join('');
                        }
                    }

                    // ✅ POLLING CORRIGÉ — lit directement le span du champ
                    document.addEventListener('DOMContentLoaded', function() {
                        var lastContent = '';
                        setInterval(function() {
                            try {
                                var rawEl  = document.querySelector('[name="perf_raw_result"] span');
                                var modeEl = document.querySelector('[name="perf_mode"] span');
                                if (!rawEl) return;
                                var raw  = (rawEl.textContent || '').trim();
                                var mode = modeEl ? (modeEl.textContent || '').trim().toLowerCase() : '';
                                if (!raw || raw === '{}' || raw === lastContent) return;
                                lastContent = raw;
                                var data = {};
                                try { data = JSON.parse(raw); } catch(e) { return; }
                                if (!data || data.error) return;
                                if (!mode || mode === 'none') {
                                    if (data.total_tickets !== undefined) mode = 'project';
                                    else if (data.members !== undefined)  mode = 'team';
                                    else if (data.velocities !== undefined) mode = 'sprint';
                                }
                                if (mode === 'project') {
                                    aiGoTab('overview', document.getElementById('aiNavOverview'));
                                    aiRenderKpis(data);
                                    aiRenderRing(data);
                                    aiRenderFeatures(data);
                                    aiRenderRisks(data);
                                    aiRenderRecs(data);
                                } else if (mode === 'team') {
                                    aiGoTab('team', document.getElementById('aiNavTeam'));
                                    aiRenderTeam(data);
                                } else if (mode === 'sprint') {
                                    aiGoTab('sprint', document.getElementById('aiNavSprint'));
                                    aiRenderSprint(data);
                                }
                                var sb = document.getElementById('aiStatusBar');
                                if (sb) sb.textContent = 'Last analysis: ' + new Date().toLocaleTimeString();
                            } catch(e) {}
                        }, 600);
                    });
